#include <stdio.h>
#include <stdlib.h>

long long gcd_ll(long long a, long long b) {
    while (b) {
        long long t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        if (gcd_ll(X, Y) > 1) {
            printf("0\n");
        } else if (gcd_ll(X + 111, Y) > 1 || gcd_ll(X, Y + 111) > 1) {
            printf("1\n");
        } else {
            printf("2\n");
        }
    }
    return 0;
}

