import sys, math

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        X = int(next(it)); Y = int(next(it))
        if math.gcd(X, Y) > 1:
            out.append('0')
        elif math.gcd(X + 111, Y) > 1 or math.gcd(X, Y + 111) > 1:
            out.append('1')
        else:
            out.append('2')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

